   163	async function authorizeMutation(
   164	  request: Request,
   165	  uploadToken: string | undefined,
   166	  unavailableCode: string,
   167	  unavailableMessage: string,
   168	): Promise<Response | null> {
   169	  if (!uploadToken) {
   170	    return apiError(503, unavailableCode, unavailableMessage);
   171	  }
   172	
   173	  const authorization = request.headers.get("authorization");
   174	  const providedToken = authorization?.startsWith("Bearer ")
   175	    ? authorization.slice("Bearer ".length)
   176	    : "";
   177	  if (!providedToken || !(await tokensMatch(providedToken, uploadToken))) {
   178	    return apiError(401, "UNAUTHORIZED", "A valid upload token is required", {
   179	      "WWW-Authenticate": "Bearer",
   180	    });
   181	  }
   182	
   183	  return null;
   184	}
