   186	function serveObject(
   187	  object: StaticFileObject | null,
   188	  headOnly: boolean,
   189	): Response {
   190	  if (!object) return apiError(404, "NOT_FOUND", "Static file not found");
   191	
   192	  const headers = new Headers({
   193	    "Cache-Control": object.metadata.cacheControl,
   194	    "Content-Length": String(object.size),
   195	    "Content-Type": object.metadata.contentType,
   196	    ETag: object.httpEtag,
   197	    "Last-Modified": object.uploaded.toUTCString(),
   198	    "X-Content-Type-Options": "nosniff",
   199	  });
   200	  setOptionalHeader(
   201	    headers,
   202	    "Content-Disposition",
   203	    object.metadata.contentDisposition,
   204	  );
   205	  setOptionalHeader(
   206	    headers,
   207	    "Content-Encoding",
   208	    object.metadata.contentEncoding,
   209	  );
   210	  setOptionalHeader(
   211	    headers,
   212	    "Content-Language",
   213	    object.metadata.contentLanguage,
   214	  );
   215	
   216	  return new Response(headOnly ? null : object.body, { headers });
   217	}
