   222	    contentType: headers.get("content-type") ?? "application/octet-stream",
   223	  };
   224	  copyHeader(headers, "content-disposition", metadata, "contentDisposition");
   225	  copyHeader(headers, "content-encoding", metadata, "contentEncoding");
   226	  copyHeader(headers, "content-language", metadata, "contentLanguage");
   227	  return metadata;
   228	}
