   230	function validateObjectKey(key: string): string | null {
   231	  if (key.length > MAX_OBJECT_KEY_LENGTH) return "The file path is too long";
   232	  if (key.includes("\\") || key.includes("\0"))
   233	    return "The file path is invalid";
   234	
   235	  const segments = key.split("/");
   236	  if (
   237	    segments.some((segment) => !segment || segment === "." || segment === "..")
   238	  ) {
   239	    return "The file path is invalid";
   240	  }
   241	
   242	  return null;
   243	}
