   245	function parseContentLength(value: string | null): number | null {
   246	  if (value === null) return null;
   247	  if (!/^\d+$/.test(value)) throw new UploadTooLargeError();
   248	
   249	  const parsed = Number(value);
   250	  if (!Number.isSafeInteger(parsed)) throw new UploadTooLargeError();
   251	  return parsed;
   252	}
