   254	async function tokensMatch(
   255	  provided: string,
   256	  expected: string,
   257	): Promise<boolean> {
   258	  const encoder = new TextEncoder();
   259	  const [providedHash, expectedHash] = await Promise.all([
   260	    crypto.subtle.digest("SHA-256", encoder.encode(provided)),
   261	    crypto.subtle.digest("SHA-256", encoder.encode(expected)),
   262	  ]);
   263	  const subtle = crypto.subtle as SubtleCrypto & {
   264	    timingSafeEqual?: (a: ArrayBuffer, b: ArrayBuffer) => boolean;
   265	  };
   266	  if (subtle.timingSafeEqual)
   267	    return subtle.timingSafeEqual(providedHash, expectedHash);
   268	
   269	  const a = new Uint8Array(providedHash);
   270	  const b = new Uint8Array(expectedHash);
   271	  let mismatch = 0;
   272	  for (let index = 0; index < a.length; index += 1)
   273	    mismatch |= a[index]! ^ b[index]!;
   274	  return mismatch === 0;
   275	}
