    35	    async delete(key) {
    36	      await bucket.delete(key);
    37	    },
    38	    async get(key) {
    39	      const object = await bucket.get(key);
    40	      return object ? toStaticFileObject(object) : null;
    41	    },
    42	    async head(key) {
    43	      const object = await bucket.head(key);
    44	      return object ? toStaticFileObject(object) : null;
    45	    },
    46	    async put(key, value, metadata: StaticFileMetadata) {
    47	      const object = await bucket.put(key, value, { httpMetadata: metadata });
    48	      return toStaticFileObject(object);
    49	    },
    50	  };
    51	}
