    33	class UploadTooLargeError extends Error {}
    34	
    35	export async function handleStaticFileRequest(
    36	  request: Request,
    37	  key: string | undefined,
    38	  storage: StaticFileStorage,
    39	  uploadToken: string | undefined,
    40	): Promise<Response> {
    41	  if (!key) return apiError(400, "INVALID_PATH", "A file path is required");
    42	  const pathError = validateObjectKey(key);
    43	  if (pathError) return apiError(400, "INVALID_PATH", pathError);
    44	
    45	  try {
    46	    switch (request.method) {
    47	      case "GET":
    48	        return serveObject(await storage.get(key), false);
    49	      case "HEAD":
    50	        return serveObject(await storage.head(key), true);
    51	      case "POST":
    52	        return uploadObject(request, key, storage, uploadToken);
    53	      default:
    54	        return apiError(405, "METHOD_NOT_ALLOWED", "Method not allowed", {
    55	          Allow: ALLOWED_METHODS,
    56	        });
    57	    }
    58	  } catch (error) {
    59	    if (error instanceof UploadTooLargeError) {
    60	      return apiError(
    61	        413,
    62	        "FILE_TOO_LARGE",
    63	        "Static files are limited to 100 MiB",
    64	      );
    65	    }
    66	
    67	    console.error(
    68	      JSON.stringify({
    69	        error: error instanceof Error ? error.message : "Unknown error",
    70	        message: "static file request failed",
    71	        method: request.method,
    72	        path: key,
    73	      }),
    74	    );
    75	    return apiError(500, "INTERNAL_ERROR", "Static file request failed");
    76	  }
    77	}
