   182	function requestMetadata(headers: Headers): StaticFileMetadata {
   183	  const metadata: StaticFileMetadata = {
   184	    cacheControl: headers.get("cache-control") ?? DEFAULT_CACHE_CONTROL,
   185	    contentType: headers.get("content-type") ?? "application/octet-stream",
   186	  };
