   193	function validateObjectKey(key: string): string | null {
   194	  if (key.length > MAX_OBJECT_KEY_LENGTH) return "The file path is too long";
   195	  if (key.includes("\\") || key.includes("\0"))
   196	    return "The file path is invalid";
   197	
   198	  const segments = key.split("/");
   199	  if (
   200	    segments.some((segment) => !segment || segment === "." || segment === "..")
   201	  ) {
   202	    return "The file path is invalid";
   203	  }
   204	
   205	  return null;
   206	}
