   208	function parseContentLength(value: string | null): number | null {
   209	  if (value === null) return null;
   210	  if (!/^\d+$/.test(value)) throw new UploadTooLargeError();
   211	
   212	  const parsed = Number(value);
   213	  if (!Number.isSafeInteger(parsed)) throw new UploadTooLargeError();
   214	  return parsed;
   215	}
