   217	async function tokensMatch(
   218	  provided: string,
   219	  expected: string,
   220	): Promise<boolean> {
   221	  const encoder = new TextEncoder();
   222	  const [providedHash, expectedHash] = await Promise.all([
   223	    crypto.subtle.digest("SHA-256", encoder.encode(provided)),
   224	    crypto.subtle.digest("SHA-256", encoder.encode(expected)),
   225	  ]);
   226	  const subtle = crypto.subtle as SubtleCrypto & {
   227	    timingSafeEqual?: (a: ArrayBuffer, b: ArrayBuffer) => boolean;
   228	  };
   229	  if (subtle.timingSafeEqual)
   230	    return subtle.timingSafeEqual(providedHash, expectedHash);
   231	
   232	  const a = new Uint8Array(providedHash);
   233	  const b = new Uint8Array(expectedHash);
   234	  let mismatch = 0;
   235	  for (let index = 0; index < a.length; index += 1)
   236	    mismatch |= a[index]! ^ b[index]!;
   237	  return mismatch === 0;
   238	}
